/* ATmega328P (Arduino Uno) cycle/parity harness for the emit_affine_kernel_c
 * `rc_predict`. avr-libc supplies the startup/vectors, so we provide main().
 *
 * Timing is deterministic: simavr is cycle-accurate, and the timed window is
 * bracketed by GPIOR0 marker writes that sim_driver.c captures at the exact
 * write instant (see that file for the GPIOR protocol). Per-step instruction
 * count is data-independent for this branch-free integer kernel, so the
 * cycle delta / T_TIME is representative.
 *
 * rc_data.h (generated by benchmarks/sparse_mcu/bench.py:_emit_data_h)
 * provides rc_fw_storage_t, RC_FW_T/K/M, g_x[], g_y_ref[].
 */
#include <avr/io.h>
#include <stdint.h>
#include "rc_data.h"

extern void rc_predict(int32_t T, const rc_fw_storage_t *X, rc_fw_storage_t *Y);

#ifndef T_TIME
#define T_TIME RC_FW_T
#endif

static rc_fw_storage_t Y[RC_FW_T * RC_FW_M];

int main(void) {
    GPIOR0 = 1;                                /* start timed region */
    rc_predict((int32_t)T_TIME, g_x, Y);
    GPIOR0 = 2;                                /* end timed region   */

    int16_t max_abs_diff = 0;
    for (int16_t i = 0; i < T_TIME * RC_FW_M; i++) {
        int16_t d = (int16_t)Y[i] - (int16_t)g_y_ref[i];
        if (d < 0) d = -d;
        if (d > max_abs_diff) max_abs_diff = d;
    }
    GPIOR1 = (max_abs_diff == 0) ? 1 : 0;      /* parity (before stop) */
    GPIOR0 = 3;                                /* all done — stop sim  */

    for (;;) { }
    return 0;
}
